import axios from 'axios'
import { exec } from 'child_process'
import fs from 'fs'
import path from 'path'
import util from 'util'
import archiver from 'archiver'
import { textOnlyMessage } from '#helper'
import { reply as sendText } from '#kadokun'
const execPromise = util.promisify(exec)


const githubRegex = /(?:https?:\/\/)?github\.com\/([A-Za-z0-9_.-]+)\/([A-Za-z0-9_.-]+)/i

/**
 * @param {import('../types/plugin.js').HandlerParams} params
 */
async function handler({ sock, m, jid, text, q }) {

  if (!textOnlyMessage(m)) return

  const noCaption = text?.includes('-c')
  const cleaned = text?.replace('-c', '').trim()


  let match = cleaned?.match(githubRegex)


  if (!match && q?.text) {
    match = q.text.match(githubRegex)
  }

  if (!match) {
    return sendText(
      sock,
      jid,
      '❌ format:\ngitclone user/repo\ngitclone https://github.com/user/repo\ngitclone link -c',
      m
    )
  }

  const owner = match[1]
  const repo = match[2].replace(/\.git$/, '')
  const repoUrl = `https://github.com/${owner}/${repo}`

  const tmpFolder = path.join(process.cwd(), 'user/temp')
  const repoPath = path.join(tmpFolder, repo)
  const zipPath = path.join(tmpFolder, `${repo}.zip`)

  try {
    if (!fs.existsSync(tmpFolder)) {
      fs.mkdirSync(tmpFolder, { recursive: true })
    }

    await sock.sendMessage(jid, {
      react: { text: '🕓', key: m.key }
    })

    // ambil info repo dari github api
    const repoInfo = await axios.get(
      `https://api.github.com/repos/${owner}/${repo}`
    )

    // clone repo
    await execPromise(`git clone --depth=1 ${repoUrl} "${repoPath}"`)

    // zip folder
    await new Promise((resolve, reject) => {
      const output = fs.createWriteStream(zipPath)
      const archive = archiver('zip', { zlib: { level: 9 } })

      archive.pipe(output)
      archive.directory(repoPath, false)
      archive.finalize()

      output.on('close', resolve)
      archive.on('error', reject)
    })

    const data = repoInfo.data

    const caption =
      `📦 *${data.full_name}*\n\n` +
      `👤 Owner: ${data.owner.login}\n` +
      `⭐ Stars: ${data.stargazers_count}\n` +
      `🍴 Forks: ${data.forks_count}\n` +
      `👀 Watchers: ${data.watchers_count}\n` +
      `📝 Language: ${data.language}\n\n` +
      `🔗 ${data.html_url}`

    await sock.sendMessage(
      jid,
      {
        document: fs.readFileSync(zipPath),
        fileName: `${repo}.zip`,
        mimetype: 'application/zip',
        ...(noCaption ? {} : { caption })
      },
      { quoted: m }
    )

    fs.rmSync(repoPath, { recursive: true, force: true })
    fs.rmSync(zipPath, { force: true })

    await sock.sendMessage(jid, {
      react: { text: '✅', key: m.key }
    })

  } catch (err) {
    console.error(err)
    await sendText(sock, jid, '❌ Gagal clone repo', m)
    await sock.sendMessage(jid, {
      react: { text: '❌', key: m.key }
    })
  }
}

