const stmt = db.prepare(`
    WITH params(day, chat_id) AS (
  SELECT :num, :chatId -- Ganti 17 dengan tanggal, 2 dengan chat_id yang dicari
),
day_start AS (
  SELECT
    strftime('%s','now','+8 hours','start of month','+'||(day-1)||' days','-8 hours') AS start_utc,
    strftime('%s','now','+8 hours','start of month','+'||day||' days','-8 hours') AS end_utc,
    chat_id
  FROM params
),
-- Menghasilkan angka 0 sampai 23 untuk baris jam
hours(hour) AS (
  SELECT 0
  UNION ALL
  SELECT hour + 1 FROM hours WHERE hour < 23
),
-- Ambil data pesan yang relevan saja dalam satu tarikan
filtered_messages AS (
  SELECT 
    CAST((m.timestamp - d.start_utc) / 3600 AS INT) AS msg_hour
  FROM messages m
  JOIN day_start d ON m.chat_id = d.chat_id
  WHERE m.timestamp >= d.start_utc 
    AND m.timestamp < d.end_utc
)
-- Gabungkan jam dengan data pesan
SELECT
  h.hour,
  COUNT(fm.msg_hour) AS total_messages
FROM hours h
LEFT JOIN filtered_messages fm ON h.hour = fm.msg_hour
GROUP BY h.hour
ORDER BY h.hour;
`)


