        let output = `📄 *File Server:* \`${path.basename(targetPath)}\`\n📍 *Lokasi:* \`${targetPath}\`\n\n\`\`\`javascript\n${content}\n\`\`\``;
        if (isCut) {
            output += '\n\n... _[Teks terlalu panjang, isi dipotong]_ ...';
        }

        await sendText(sock, jid, output, m);

    } catch (err) {
        console.error(err);
        await sendText(sock, jid, `❌ *Gagal membaca file server:*\n${err.message}`, m);
    }
}

