async function handler({ sock, m, text, jid }) {
    // 1. Ambil link pakai Regex biar akurat
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const match = text.match(urlRegex);
    const link = match ? match[0] : null;

    if (!link) {
        await sendText(sock, jid, `Mana link videonya bro? Contoh: *dl https://www.tiktok.com/xxxx*`, m)
        return
    }

    await sendText(sock, jid, `Sabar ya, lagi gue proses videonya... ⏳`, m)

    let videoUrl = null;
    let captionText = `Nih bro videonya! \n\n🚀 Downloaded by Near Bot`;

    // ==========================================
    // PERCOBAAN 1: MENGGUNAKAN API PERTAMA
    // ==========================================
    try {
        const options1 = {
            method: 'GET',
            headers: {
                'x-rapidapi-key': '83d4a80525mshfa81d050a70312fp1347dcjsnf5e0f5e9c9c5', 
                'x-rapidapi-host': 'all-in-one-video-downloader-api-tiktok-ig-fb.p.rapidapi.com'
            }
        };
        const apiUrl1 = `https://all-in-one-video-downloader-api-tiktok-ig-fb.p.rapidapi.com/all-downloader.php?url=${encodeURIComponent(link)}`;

        const response1 = await fetch(apiUrl1, options1);
        const result1 = await response1.json();

        // Ambil link video sesuai struktur JSON API pertama
        videoUrl = result1?.videos?.[0]?.download_url;
    } catch (error) {
        console.log('[API 1 Failed]:', error.message);
    }

    // ==========================================
    // PERCOBAAN 2: FALLBACK KE API KEDUA
    // ==========================================
    if (!videoUrl) {
        console.log('API 1 gagal ngekstrak, otomatis ganti ke Fallback API...');

        try {
            // Masukin link ke body form-urlencoded
            const encodedParams = new URLSearchParams();
            encodedParams.set('url', link); 

            const options2 = {
                method: 'POST',
                headers: {
                    'x-rapidapi-key': '83d4a80525mshfa81d050a70312fp1347dcjsnf5e0f5e9c9c5',
                    'x-rapidapi-host': 'all-in-one-video-downloader.p.rapidapi.com',
                    'Content-Type': 'application/x-www-form-urlencoded'
                },
                body: encodedParams
            };

            const response2 = await fetch('https://all-in-one-video-downloader.p.rapidapi.com/index.php', options2);
            const result2 = await response2.json(); // Tetep di-parse sebagai JSON biar gampang diambil

            // Ambil link video sesuai struktur JSON Fallback yang lu kasih
            // Biasanya ambil index 0 buat kualitas HD
            videoUrl = result2?.medias?.videos?.[0]?.url;

            // Kalau ada judulnya, kita tambahin ke caption WA
            if (result2?.title) {
                captionText = `*${result2.title.trim()}*\n\nNih bro videonya! \n🚀 Downloaded by Near Bot`;
            }

        } catch (error) {
            console.log('[Fallback API Failed]:', error.message);
        }
    }

    // ==========================================
    // HASIL AKHIR: CEK APAKAH LINK DAPAT
    // ==========================================
    if (!videoUrl) {
        await sendText(sock, jid, `Duh, udah dicoba pake dua server tetep gagal ngekstrak link videonya nih bro. Server API-nya lagi pada ngambek kayaknya.`, m);
        return;
    }

    // Eksekusi kirim video ke WhatsApp
    try {
        await sock.sendMessage(jid, { 
            video: { url: videoUrl }, 
            caption: captionText 
        }, { quoted: m });
    } catch (error) {
        console.error('[Error Sending Video]:', error)
        await sendText(sock, jid, `Link videonya dapet, tapi pas dikirim ke WA error. Biasanya karena file videonya kegedean.`, m)
    }
}

