import { textOnlyMessage, sendText } from '#helper'
import { smartChat } from '../../system/services/ai-service.js'
import { addMessage, buildContext, resetSession } from '../../system/services/conversation-manager.js'

/**
 * @param {import('../../system/types/plugin.js').HandlerParams} params
 */
async function handler({ sock, m, q, text, jid, command, prefix }) {
    // Pastikan cuma ngerespon pesan teks biasa
    if (!textOnlyMessage(m)) return

    // Handle reset memory jika user ketik "mal reset"
    if (text?.toLowerCase().trim() === 'reset') {
        const success = resetSession(jid)
        return sendText(sock, jid, success ? '✅ Memori chat kita hapus mi, mulai maki\' baru lagi nah.' : 'Konteks memang sudah kosong ji.', m)
    }

    const quotedText = q?.text || ''
    const userPrompt = (text || '').trim()

    // Gunakan prompt yang bersih untuk disimpan di memori
    const cleanInput = userPrompt || (quotedText ? '[Merujuk pesan]' : '')

    if (!cleanInput && !quotedText) {
        await sendText(sock, jid, `Oit, kenapa? Ada ji yang bisa kubantu?`, m)
        return
    }

    // Gabungkan input jika ada reply untuk dikirim ke AI
    const fullInput = quotedText
        ? `${userPrompt}\n\n[User merujuk ke pesan ini]: "${quotedText}"`.trim()
        : userPrompt

    // Tambahkan pesan user ke memori
    addMessage(jid, 'user', cleanInput)

    // Ambil riwayat percakapan (context)
    const historyCtx = buildContext(jid)

    // System Prompt - Near si Anak Makassar
    const systemPrompt = `Nama kamu adalah Near. Kamu adalah teman ngobrol yang asik di WhatsApp, cerdas, dan punya banyak pengetahuan umum.
ATURAN MAIN:
1. WAJIB pakai gaya bahasa Makassar yang santai, akrab, dan natural.
2. Gunakan imbuhan khas Makassar: ji, mi, ki, pi, mako, bede, di', tawwa, nah.
3. Jangan kaku, balas singkat dan padat layaknya orang Makassar yang sedang chattingan.
4. Kamu punya akses ke berbagai model AI canggih (Llama 3.3, GPT-4o, Gemini 2.0). Berikan jawaban terbaikmu.
5. Panggilan kamu adalah "mal".
6. Gunakan CONTEXT RIWAYAT di bawah ini agar jawabanmu nyambung:

[CONTEXT RIWAYAT CHAT]:
${historyCtx}`

    try {
        // Panggil Master AI Service (7 Pillar Waterfall)
        // Ini otomatis rotasi API Key dan Model kalau ada yang limit
        const result = await smartChat(fullInput, systemPrompt)

        if (result.success) {
            // Kirim balasan
            await sendText(sock, jid, result.content, m)

            // Simpan balasan AI ke memori
            addMessage(jid, 'assistant', result.content)
        } else {
            throw new Error(result.error || 'Semua sistem AI sibuk')
        }

    } catch (error) {
        console.error('[Error Near AI Merge]:', error)
        await sendText(sock, jid, `Waduh, semua otakku lagi nge-lag (Limit di semua provider). Coba lagi pi nanti nah.\n\nDetail: ${error.message.slice(0, 100)}`, m)
    }
}

