/**
 * @param {import('../../system/types/plugin.js').HandlerParams} params
 */
async function handler({ sock, m, text, chatId }) {
    // Pastiin cuma dieksekusi di dalem grup
    if (!chatId.endsWith('@g.us')) {
        await sendText(sock, chatId, 'Fitur SWGC (Story Grup) ini cuma bisa dipake di dalem grup bro.', m)
        return
    }

    // Tentukan target pesan (kalau reply ambil m.q, kalau ngetik langsung ambil m)
    const targetMsg = m.q ? m.q.message : m.message
    const targetType = m.q ? m.q.type : m.type

    if (!targetMsg) return

    // Bikin object contextInfo khusus buat Story Grup
    const customContextInfo = {
        remoteJid: chatId,
        isGroupStatus: true
    }

    const content = {}

    try {
        // SKENARIO 1: Teks
        if (targetType === 'conversation' || targetType === 'extendedTextMessage') {
            const storyText = m.q ? m.q.text : text

            if (!storyText) {
                await sendText(sock, chatId, 'Teksnya mana bro? Contoh: swgc tes story', m)
                return
            }

            content.extendedTextMessage = {
                text: storyText,
                contextInfo: customContextInfo
            }
        } 
        // SKENARIO 2: Gambar
        else if (targetType === 'imageMessage') {
            content.imageMessage = {
                ...targetMsg.imageMessage, // Copy semua properti gambar aslinya (URL, mediaKey, dll)
                contextInfo: {
                    ...(targetMsg.imageMessage.contextInfo || {}),
                    ...customContextInfo
                }
            }
            // Kalau lu ngetik teks pas nge-reply gambar, teksnya dijadiin caption
            if (text) content.imageMessage.caption = text 
        } 
        // SKENARIO 3: Video
        else if (targetType === 'videoMessage') {
            content.videoMessage = {
                ...targetMsg.videoMessage,
                contextInfo: {
                    ...(targetMsg.videoMessage.contextInfo || {}),
                    ...customContextInfo
                }
            }
            if (text) content.videoMessage.caption = text
        } 
        else {
            await sendText(sock, chatId, 'Cuma support teks, gambar, sama video ya buat dijadiin story grup.', m)
            return
        }

        // Tembak pesannya balik ke grup sebagai Group Status
        await sock.relayMessage(chatId, content, {})

    } catch (error) {
        console.error('[Error SWGC Relay]:', error)
        await sendText(sock, chatId, 'Waduh, gagal nge-relay story grup nih. Cek terminal ya.', m)
    }
}

