async function handler({ sock, m, jid, text, q }) {
  const messageText = (text || "").toLowerCase();

  // Logika pemicu untuk withoutContext
  // Bot hanya akan merespons jika ada command `.ai` ATAU jika pesan mengandung kata 'near' atau 'mal'.
  const triggerWords = ["near", "mal"];
  const isTriggeredByKeyword = triggerWords.some(word => messageText.includes(word));

  // Jika tidak ada command dan tidak ada keyword, hentikan.
  if (m.command !== 'ai' && m.command !== 'near' && m.command !== 'mal' && !isTriggeredByKeyword) {
    return;
  }

  let userText = text?.trim() || "";
  let quotedText = q?.text?.trim() || "";
  let finalPrompt = "";

  // Menggabungkan teks dari pengguna dan teks yang di-reply
  if (userText && quotedText) {
    finalPrompt = `[Konteks pesan yang aku reply: "${quotedText}"]\n\n${userText}`;
  } else if (userText) {
    finalPrompt = userText;
  } else if (quotedText) {
    finalPrompt = quotedText;
  }

