  if (!command && !isTriggeredByKeyword) {
    return;
  }

  let userText = text?.trim() || "";
  let quotedText = q?.text?.trim() || "";
  let finalPrompt = "";

  if (userText && quotedText) {
    finalPrompt = `[Konteks pesan yang aku reply: "${quotedText}"]\n\n${userText}`;
  } else if (userText) {
    finalPrompt = userText;
  } else if (quotedText) {
    finalPrompt = quotedText;
  }

  if (command) {
    finalPrompt = finalPrompt.replace(new RegExp(`^\\.${command}\\s*`), '').trim();
  }

  if (!finalPrompt) {
    return await sendText(sock, jid, "Ya, ada yang bisa dibantu?", m);
  }

  // React dicabut biar nggak berisik

  try {
    const db = await getDb();
    const sessionJid = m.senderId || jid;

    const row = await db.get(`SELECT history FROM chat_session WHERE session_id = ?`, [sessionJid]);
    let historyArr = [];
    if (row && row.history) {
      try { historyArr = JSON.parse(row.history); } catch (e) {}
    }

    let historyLog = historyArr.map(h => `${h.role === 'user' ? 'User' : 'Near Bot'}: ${h.msg}`).join('\n');
    let injectedPrompt = `${PERSONA}\n${historyLog}\n\nUser: ${finalPrompt}\nNear Bot:`;

    const chatGpt = new ChatGpt();
    const response = await chatGpt.startConversation(injectedPrompt, false, false);

    if (!response || !response.msg) {
      throw new Error("Gagal terhubung ke AI Service.");
    }

    let replyText = response.msg;
    if (replyText.startsWith("Near Bot:")) replyText = replyText.replace("Near Bot:", "").trim();

    await sendText(sock, jid, replyText, m);
    // React sukses dicabut

    historyArr.push({ role: 'user', msg: finalPrompt });
    historyArr.push({ role: 'bot', msg: replyText });

    if (historyArr.length > 10) {
      historyArr = historyArr.slice(historyArr.length - 10);
    }

    await db.run(
      `INSERT INTO chat_session (session_id, history) VALUES (?, ?) ON CONFLICT(session_id) DO UPDATE SET history = excluded.history`,
      [sessionJid, JSON.stringify(historyArr)]
    );

  } catch (err) {
    console.error(err);
    await sendText(sock, jid, `❌ Terjadi error:\n${err.message}`, m);
    // React error dicabut
  }
}

